starterCode:
function createCounter(initialValue: number = 0): {
  increment: () => number;
  decrement: () => number;
  reset: () => number;
  getValue: () => number;
} {
  // Keep count in a variable captured by closure, not on the returned object
  // increment/decrement should mutate it and return the new value
  // reset should restore initialValue
}

solution:
function createCounter(initialValue: number = 0): {
  increment: () => number;
  decrement: () => number;
  reset: () => number;
  getValue: () => number;
} {
  let count = initialValue;

  return {
    increment: () => ++count,
    decrement: () => --count,
    reset: () => {
      count = initialValue;
      return count;
    },
    getValue: () => count
  };
}

