function discountProducts(
  products: Array<{ name: string; price: number }>,
  minPrice: number,
  discountPercent: number
): Array<{ name: string; discountedPrice: number }> {
  // 1. filter out products below minPrice or with price <= 0
  // 2. map remaining products to { name, discountedPrice }
}

solution:
function discountProducts(
  products: Array<{ name: string; price: number }>,
  minPrice: number,
  discountPercent: number
): Array<{ name: string; discountedPrice: number }> {
  return products
    .filter(product => product.price >= minPrice && product.price > 0)
    .map(product => ({
      name: product.name,
      discountedPrice: product.price * (1 - discountPercent / 100)
    }));
}

