solution:
interface Subscriber<T> {
  next(value: T): void;
  error(err: Error): void;
  complete(): void;
}

type Unsubscribe = () => void;
type ObservableFunction<T> = (subscriber: Subscriber<T>) => void | Unsubscribe;
type Operator<T, R> = (source: Observable<T>) => Observable<R>;

class Observable<T> {
  constructor(private observableFn: ObservableFunction<T>) {}

  subscribe(subscriberOrNext: Partial<Subscriber<T>> | ((value: T) => void)): Subscription {
    const subscriber: Subscriber<T> = typeof subscriberOrNext === 'function'
      ? {
          next: subscriberOrNext,
          error: (err) => { throw err; },
          complete: () => {}
        }
      : {
          next: () => {},
          error: (err) => { throw err; },
          complete: () => {},
          ...subscriberOrNext
        };

    const unsubscribe = this.observableFn(subscriber) || (() => {});
    return new Subscription(unsubscribe);
  }

  pipe(...operators: Operator<any, any>[]): Observable<any> {
    return operators.reduce((source, operator) => operator(source), this);
  }
}

class Subscription {
  private unsubscribed: boolean = false;

  constructor(private unsubscribeFn: () => void) {}

  unsubscribe(): void {
    if (!this.unsubscribed) {
      this.unsubscribed = true;
      this.unsubscribeFn();
    }
  }
}

function map<T, R>(fn: (value: T) => R): Operator<T, R> {
  return (source: Observable<T>) => new Observable<R>(subscriber => {
    return source.subscribe({
      next: (value) => {
        try {
          subscriber.next(fn(value));
        } catch (err) {
          subscriber.error(err instanceof Error ? err : new Error(String(err)));
        }
      },
      error: (err) => subscriber.error(err),
      complete: () => subscriber.complete()
    });
  });
}

function filter<T>(predicate: (value: T) => boolean): Operator<T, T> {
  return (source: Observable<T>) => new Observable<T>(subscriber => {
    return source.subscribe({
      next: (value) => {
        try {
          if (predicate(value)) {
            subscriber.next(value);
          }
        } catch (err) {
          subscriber.error(err instanceof Error ? err : new Error(String(err)));
        }
      },
      error: (err) => subscriber.error(err),
      complete: () => subscriber.complete()
    });
  });
}

function tap<T>(fn: (value: T) => void): Operator<T, T> {
  return (source: Observable<T>) => new Observable<T>(subscriber => {
    return source.subscribe({
      next: (value) => {
        try {
          fn(value);
        } catch (err) {
          subscriber.error(err instanceof Error ? err : new Error(String(err)));
        }
        subscriber.next(value);
      },
      error: (err) => subscriber.error(err),
      complete: () => subscriber.complete()
    });
  });
}

function take<T>(count: number): Operator<T, T> {
  return (source: Observable<T>) => new Observable<T>(subscriber => {
    let emitted = 0;
    const subscription = source.subscribe({
      next: (value) => {
        if (emitted < count) {
          subscriber.next(value);
          emitted++;
          if (emitted === count) {
            subscriber.complete();
            subscription.unsubscribe();
          }
        }
      },
      error: (err) => subscriber.error(err),
      complete: () => subscriber.complete()
    });
    return () => subscription.unsubscribe();
  });
}

function catchError<T>(handler: (err: Error) => Observable<T>): Operator<T, T> {
  return (source: Observable<T>) => new Observable<T>(subscriber => {
    return source.subscribe({
      next: (value) => subscriber.next(value),
      error: (err) => {
        try {
          const result = handler(err);
          return result.subscribe(subscriber);
        } catch (e) {
          subscriber.error(e instanceof Error ? e : new Error(String(e)));
        }
      },
      complete: () => subscriber.complete()
    });
  });
}

function retry<T>(times: number = 1): Operator<T, T> {
  return (source: Observable<T>) => new Observable<T>(subscriber => {
    let attempts = 0;
    const attemptSubscription = () => {
      return source.subscribe({
        next: (value) => subscriber.next(value),
        error: (err) => {
          attempts++;
          if (attempts < times) {
            attemptSubscription();
          } else {
            subscriber.error(err);
          }
        },
        complete: () => subscriber.complete()
      });
    };
    return () => attemptSubscription().unsubscribe();
  });
}

description.en:
Implement an async queue that processes tasks with a maximum concurrency limit. The queue should:

- Accept tasks (functions returning promises)
- Process tasks in FIFO order up to N concurrent operations
- Provide methods to enqueue tasks and wait for all to complete
- Handle rejection gracefully without stopping other tasks
- Return results in the order tasks were enqueued

**Signature:**
typescript
class AsyncQueue {
  constructor(concurrency: number);
  enqueue<T>(task: () => Promise<T>): Promise<T>;
  waitAll(): Promise<void>;
}


**Example:**

const queue = new AsyncQueue(2);
const results: number[] = [];

queue.enqueue(async () => { await delay(100); return 1; }).then(r => results.push(r));
queue.enqueue(async () => { await delay(50); return 2; }).then(r => results.push(r));
queue.enqueue(async () => { await delay(75); return 3; }).then(r => results.push(r));

await queue.waitAll();
console.log(results); // [1, 2, 3] in enqueue order


**Edge cases:**
- Tasks that reject should not block the queue
- Concurrent limit must be enforced strictly
- Results must be returned in enqueue order, not completion order

