class AsyncQueue {
  private concurrency: number;
  private running: number = 0;
  private queue: Array<() => Promise<any>> = [];
  private waiters: Array<() => void> = [];

  constructor(concurrency: number) {
    this.concurrency = concurrency;
  }

  enqueue<T>(task: () => Promise<T>): Promise<T> {
    return new Promise<T>((resolve, reject) => {
      this.queue.push(async () => {
        try {
          const result = await task();
          resolve(result);
        } catch (error) {
          reject(error);
        }
      });
      this.process();
    });
  }

  waitAll(): Promise<void> {
    return new Promise((resolve) => {
      if (this.running === 0 && this.queue.length === 0) {
        resolve();
      } else {
        this.waiters.push(resolve);
      }
    });
  }

  private process(): void {
    while (this.running < this.concurrency && this.queue.length > 0) {
      this.running++;
      const task = this.queue.shift()!;
      task().finally(() => {
        this.running--;
        if (this.running === 0 && this.queue.length === 0) {
          const waiter = this.waiters.shift();
          if (waiter) waiter();
        }
        this.process();
      });
    }
  }
}

description.en:
Implement a reactive Observable class that follows the observer pattern. Requirements:

- Support subscribing with observer functions (next, error, complete)
- Implement chainable operators: map, filter, take, catchError
- Handle subscription cleanup with unsubscribe
- Execute lazy evaluation (only when subscribed)
- Support multiple subscribers independently

**Signature:**
typescript
class Observable<T> {
  constructor(subscribe: (observer: Observer<T>) => Unsubscribe);
  subscribe(observer: Partial<Observer<T>>): Subscription;
  map<U>(fn: (value: T) => U): Observable<U>;
  filter(predicate: (value: T) => boolean): Observable<T>;
  take(count: number): Observable<T>;
  catchError(handler: (error: Error) => Observable<T>): Observable<T>;
}

interface Observer<T> {
  next?: (value: T) => void;
  error?: (error: Error) => void;
  complete?: () => void;
}

interface Subscription {
  unsubscribe(): void;
}


**Example:**

const obs = new Observable<number>((observer) => {
  observer.next?.(1);
  observer.next?.(2);
  observer.next?.(3);
  observer.complete?.();
  return () => console.log('cleaned up');
});

const results: number[] = [];
obs
  .filter(x => x > 1)
  .map(x => x * 2)
  .take(1)
  .subscribe({
    next: (x) => results.push(x),
    complete: () => console.log('done')
  });

console.log(results); // [4]


**Edge cases:**
- Multiple subscriptions should not interfere
- Unsubscribe should prevent further emissions
- Errors should propagate through the chain
- take() should complete after N values

